INSERT INTO public.agents (slug, name, description, category, icon, credit_cost, active) VALUES ('adaptacao-inclusiva', 'Especialista em Adaptação Inclusiva de Aulas', 'Adapte qualquer aula para alunos neurodivergentes ou com deficiência. Envie seu material, escolha o perfil do aluno (TDAH, TEA, Dislexia, Deficiência Auditiva, Visual, de Fala, Intelectual, Altas Habilidades) e receba um plano completo com estratégias pedagógicas, tecnologias assistivas, plataformas e mídias acessíveis.', 'EdTech e Professores 4.0', 'UserRound', 1, true);